import{_ as n,c as a,o as t,a1 as s}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse(`{"title":"Révision de plan : réviser visuellement les plans IA | Plannotator","description":"Apprenez la fonctionnalité de révision de plan de Plannotator. Utilisez l'interface visuelle pour réviser les plans générés par l'IA, ajoutez des annotations pour approuver ou rejeter, et maîtrisez la différence entre Approve et Request Changes.","frontmatter":{"title":"Révision de plan : réviser visuellement les plans IA | Plannotator","subtitle":"Bases de la révision de plan : réviser visuellement les plans IA","description":"Apprenez la fonctionnalité de révision de plan de Plannotator. Utilisez l'interface visuelle pour réviser les plans générés par l'IA, ajoutez des annotations pour approuver ou rejeter, et maîtrisez la différence entre Approve et Request Changes.","sidebarTitle":"Apprendre à réviser un plan en 5 min","tags":["Révision de plan","Révision visuelle","Annotations","Approbation","Rejet","Claude Code","OpenCode"],"prerequisite":["start-getting-started"],"order":1},"headers":[],"relativePath":"fr/backnotprop/plannotator/platforms/plan-review-basics/index.md","filePath":"fr/backnotprop/plannotator/platforms/plan-review-basics/index.md"}`),o={name:"fr/backnotprop/plannotator/platforms/plan-review-basics/index.md"};function l(r,e,i,p,u,d){return t(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="bases-de-la-revision-de-plan-reviser-visuellement-les-plans-ia" tabindex="-1">Bases de la révision de plan : réviser visuellement les plans IA <a class="header-anchor" href="#bases-de-la-revision-de-plan-reviser-visuellement-les-plans-ia" aria-label="Permalink to &quot;Bases de la révision de plan : réviser visuellement les plans IA&quot;">​</a></h1><h2 id="ce-que-vous-pourrez-faire-apres-ce-cours" tabindex="-1">Ce que vous pourrez faire après ce cours <a class="header-anchor" href="#ce-que-vous-pourrez-faire-apres-ce-cours" aria-label="Permalink to &quot;Ce que vous pourrez faire après ce cours&quot;">​</a></h2><ul><li>✅ Utiliser l&#39;interface visuelle de Plannotator pour réviser les plans générés par l&#39;IA</li><li>✅ Sélectionner du texte de plan et ajouter différents types d&#39;annotations (suppression, remplacement, commentaire)</li><li>✅ Approuver un plan pour que l&#39;IA continue l&#39;implémentation</li><li>✅ Rejeter un plan en envoyant vos annotations comme retour à l&#39;IA</li><li>✅ Comprendre les cas d&#39;utilisation et les différences entre les types d&#39;annotations</li></ul><h2 id="votre-probleme-actuel" tabindex="-1">Votre problème actuel <a class="header-anchor" href="#votre-probleme-actuel" aria-label="Permalink to &quot;Votre problème actuel&quot;">​</a></h2><p><strong>Problème 1</strong> : Les plans d&#39;implémentation générés par l&#39;IA sont difficiles à lire dans le terminal — trop de texte, structure peu claire, révision fatigante.</p><p><strong>Problème 2</strong> : Pour donner un retour à l&#39;IA, vous devez décrire textuellement « supprimer le 3e paragraphe », « modifier cette fonction » — coût de communication élevé, et l&#39;IA peut mal comprendre.</p><p><strong>Problème 3</strong> : Certaines parties du plan n&#39;ont pas besoin de modification, d&#39;autres doivent être remplacées, d&#39;autres nécessitent des commentaires, mais aucun outil ne vous aide à structurer ces retours.</p><p><strong>Problème 4</strong> : Vous ne savez pas comment indiquer à l&#39;IA si vous avez approuvé le plan ou s&#39;il nécessite des modifications.</p><p><strong>Plannotator peut vous aider</strong> :</p><ul><li>Interface visuelle au lieu de la lecture en terminal, structure claire</li><li>Sélectionnez du texte pour ajouter des annotations (suppression, remplacement, commentaire), retour précis</li><li>Les annotations sont automatiquement converties en données structurées, l&#39;IA comprend précisément votre intention</li><li>Approbation ou rejet en un clic, l&#39;IA répond immédiatement</li></ul><h2 id="quand-utiliser-cette-approche" tabindex="-1">Quand utiliser cette approche <a class="header-anchor" href="#quand-utiliser-cette-approche" aria-label="Permalink to &quot;Quand utiliser cette approche&quot;">​</a></h2><p><strong>Cas d&#39;utilisation</strong> :</p><ul><li>L&#39;agent IA termine un plan et appelle <code>ExitPlanMode</code> (Claude Code)</li><li>L&#39;agent IA appelle l&#39;outil <code>submit_plan</code> (OpenCode)</li><li>Vous devez réviser un plan d&#39;implémentation généré par l&#39;IA</li><li>Vous devez fournir des retours précis sur les modifications du plan</li></ul><p><strong>Cas non applicables</strong> :</p><ul><li>Laisser l&#39;IA implémenter directement le code (sans révision de plan)</li><li>Plan déjà approuvé, vous devez réviser les modifications de code réelles (utilisez la fonctionnalité de revue de code)</li></ul><h2 id="🎒-preparation-avant-de-commencer" tabindex="-1">🎒 Préparation avant de commencer <a class="header-anchor" href="#🎒-preparation-avant-de-commencer" aria-label="Permalink to &quot;🎒 Préparation avant de commencer&quot;">​</a></h2><p><strong>Prérequis</strong> :</p><ul><li>✅ Plannotator CLI installé (voir <a href="./../../start/getting-started/">Démarrage rapide</a>)</li><li>✅ Plugin Claude Code ou OpenCode configuré (voir le guide d&#39;installation correspondant)</li><li>✅ Agent IA supportant la révision de plan (Claude Code 2.1.7+ ou OpenCode)</li></ul><p><strong>Méthodes de déclenchement</strong> :</p><ul><li><strong>Claude Code</strong> : L&#39;IA appelle automatiquement <code>ExitPlanMode</code> après avoir terminé le plan, Plannotator se lance automatiquement</li><li><strong>OpenCode</strong> : L&#39;IA appelle l&#39;outil <code>submit_plan</code>, Plannotator se lance automatiquement</li></ul><h2 id="concept-central" tabindex="-1">Concept central <a class="header-anchor" href="#concept-central" aria-label="Permalink to &quot;Concept central&quot;">​</a></h2><h3 id="qu-est-ce-que-la-revision-de-plan" tabindex="-1">Qu&#39;est-ce que la révision de plan <a class="header-anchor" href="#qu-est-ce-que-la-revision-de-plan" aria-label="Permalink to &quot;Qu&#39;est-ce que la révision de plan&quot;">​</a></h3><p>La <strong>révision de plan</strong> est la fonctionnalité principale de Plannotator, utilisée pour réviser visuellement les plans d&#39;implémentation générés par l&#39;IA.</p><div class="info custom-block"><p class="custom-block-title">Pourquoi avez-vous besoin de la révision de plan ?</p><p>Après avoir généré un plan, l&#39;IA demande généralement « Ce plan vous convient-il ? » ou « Dois-je commencer l&#39;implémentation ? ». Sans outil visuel, vous ne pouvez que lire le plan en texte brut dans le terminal, puis répondre par des retours vagues comme « OK », « Non, modifiez XX ». Plannotator vous permet de visualiser le plan, de sélectionner précisément les parties à modifier, d&#39;ajouter des annotations structurées, et l&#39;IA comprend plus facilement votre intention.</p></div><h3 id="flux-de-travail" tabindex="-1">Flux de travail <a class="header-anchor" href="#flux-de-travail" aria-label="Permalink to &quot;Flux de travail&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  Agent IA      │</span></span>
<span class="line"><span>│  (génère plan) │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         │ ExitPlanMode / submit_plan</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│ Plannotator UI  │  ← Le navigateur s&#39;ouvre automatiquement</span></span>
<span class="line"><span>│                 │</span></span>
<span class="line"><span>│ ┌───────────┐  │</span></span>
<span class="line"><span>│ │ Contenu   │  │</span></span>
<span class="line"><span>│ │ du plan   │  │</span></span>
<span class="line"><span>│ │ (Markdown) │  │</span></span>
<span class="line"><span>│ └───────────┘  │</span></span>
<span class="line"><span>│       │         │</span></span>
<span class="line"><span>│       │ Sélectionner du texte</span></span>
<span class="line"><span>│       ▼         │</span></span>
<span class="line"><span>│ ┌───────────┐  │</span></span>
<span class="line"><span>│ │ Ajouter   │  │</span></span>
<span class="line"><span>│ │ annotation│  │</span></span>
<span class="line"><span>│ │ Delete/   │  │</span></span>
<span class="line"><span>│ │ Replace/  │  │</span></span>
<span class="line"><span>│ │ Comment   │  │</span></span>
<span class="line"><span>│ └───────────┘  │</span></span>
<span class="line"><span>│       │         │</span></span>
<span class="line"><span>│       ▼         │</span></span>
<span class="line"><span>│ ┌───────────┐  │</span></span>
<span class="line"><span>│ │ Décision  │  │</span></span>
<span class="line"><span>│ │ Approve/  │  │</span></span>
<span class="line"><span>│ │ Request   │  │</span></span>
<span class="line"><span>│ │ Changes   │  │</span></span>
<span class="line"><span>│ └───────────┘  │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         │ {&quot;behavior&quot;: &quot;allow&quot;} ou</span></span>
<span class="line"><span>         │ {&quot;behavior&quot;: &quot;deny&quot;, &quot;message&quot;: &quot;...&quot;}</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  Agent IA      │</span></span>
<span class="line"><span>│  (continue     │</span></span>
<span class="line"><span>│  implémentation)│</span></span>
<span class="line"><span>└─────────────────┘</span></span></code></pre></div><h3 id="types-d-annotations" tabindex="-1">Types d&#39;annotations <a class="header-anchor" href="#types-d-annotations" aria-label="Permalink to &quot;Types d&#39;annotations&quot;">​</a></h3><p>Plannotator prend en charge quatre types d&#39;annotations, chacun avec un usage différent :</p><table tabindex="0"><thead><tr><th>Type d&#39;annotation</th><th>Utilisation</th><th>Retour reçu par l&#39;IA</th></tr></thead><tbody><tr><td><strong>Delete</strong></td><td>Supprimer le contenu non nécessaire</td><td>« Supprimer : [texte sélectionné] »</td></tr><tr><td><strong>Replace</strong></td><td>Remplacer par un meilleur contenu</td><td>« Remplacer : [texte sélectionné] par [votre texte] »</td></tr><tr><td><strong>Comment</strong></td><td>Commenter un passage sans exiger de modification</td><td>« Commentaire : [texte sélectionné]. Note : [votre commentaire] »</td></tr><tr><td><strong>Global Comment</strong></td><td>Commentaire global, non lié à un texte spécifique</td><td>« Commentaire global : [votre commentaire] »</td></tr></tbody></table><h3 id="approve-vs-request-changes" tabindex="-1">Approve vs Request Changes <a class="header-anchor" href="#approve-vs-request-changes" aria-label="Permalink to &quot;Approve vs Request Changes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type de décision</th><th>Action</th><th>Retour reçu par l&#39;IA</th><th>Cas d&#39;utilisation</th></tr></thead><tbody><tr><td><strong>Approve</strong></td><td>Cliquer sur le bouton Approve</td><td><code>{&quot;behavior&quot;: &quot;allow&quot;}</code></td><td>Le plan est correct, approbation directe</td></tr><tr><td><strong>Request Changes</strong></td><td>Cliquer sur le bouton Request Changes</td><td><code>{&quot;behavior&quot;: &quot;deny&quot;, &quot;message&quot;: &quot;...&quot;}</code></td><td>Des modifications sont nécessaires</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Différences entre Claude Code et OpenCode</p><ul><li><strong>Claude Code</strong> : Les annotations ne sont pas envoyées lors de l&#39;approbation (elles sont ignorées)</li><li><strong>OpenCode</strong> : Les annotations peuvent être envoyées comme notes lors de l&#39;approbation (optionnel)</li></ul><p><strong>Lors du rejet du plan</strong> : Sur les deux plateformes, les annotations sont envoyées à l&#39;IA</p></div><h2 id="suivez-les-etapes" tabindex="-1">Suivez les étapes <a class="header-anchor" href="#suivez-les-etapes" aria-label="Permalink to &quot;Suivez les étapes&quot;">​</a></h2><h3 id="etape-1-declencher-la-revision-de-plan" tabindex="-1">Étape 1 : Déclencher la révision de plan <a class="header-anchor" href="#etape-1-declencher-la-revision-de-plan" aria-label="Permalink to &quot;Étape 1 : Déclencher la révision de plan&quot;">​</a></h3><p><strong>Exemple Claude Code</strong> :</p><p>Dialoguez avec l&#39;IA dans Claude Code pour qu&#39;elle génère un plan d&#39;implémentation :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Utilisateur : Aide-moi à créer un plan d&#39;implémentation pour un module d&#39;authentification utilisateur</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Claude : D&#39;accord, voici le plan d&#39;implémentation :</span></span>
<span class="line"><span>1. Créer le modèle utilisateur</span></span>
<span class="line"><span>2. Implémenter l&#39;API d&#39;inscription</span></span>
<span class="line"><span>3. Implémenter l&#39;API de connexion</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>(L&#39;IA appelle ExitPlanMode)</span></span></code></pre></div><p><strong>Exemple OpenCode</strong> :</p><p>Dans OpenCode, l&#39;IA appelle automatiquement l&#39;outil <code>submit_plan</code>.</p><p><strong>Ce que vous devriez voir</strong> :</p><ol><li>Le navigateur ouvre automatiquement l&#39;interface Plannotator</li><li>Le contenu du plan généré par l&#39;IA s&#39;affiche (format Markdown)</li><li>Les boutons « Approve » et « Request Changes » apparaissent en bas de page</li></ol><h3 id="etape-2-parcourir-le-contenu-du-plan" tabindex="-1">Étape 2 : Parcourir le contenu du plan <a class="header-anchor" href="#etape-2-parcourir-le-contenu-du-plan" aria-label="Permalink to &quot;Étape 2 : Parcourir le contenu du plan&quot;">​</a></h3><p>Consultez le plan dans le navigateur :</p><ul><li>Le plan est rendu en format Markdown, incluant titres, paragraphes, listes, blocs de code</li><li>Vous pouvez faire défiler pour voir l&#39;ensemble du plan</li><li>Support du mode clair/sombre (cliquez sur le bouton de changement de thème en haut à droite)</li></ul><h3 id="etape-3-selectionner-du-texte-et-ajouter-des-annotations" tabindex="-1">Étape 3 : Sélectionner du texte et ajouter des annotations <a class="header-anchor" href="#etape-3-selectionner-du-texte-et-ajouter-des-annotations" aria-label="Permalink to &quot;Étape 3 : Sélectionner du texte et ajouter des annotations&quot;">​</a></h3><p><strong>Ajouter une annotation Delete</strong> :</p><ol><li>Sélectionnez avec la souris le texte à supprimer dans le plan</li><li>Cliquez sur le bouton <strong>Delete</strong> dans la barre d&#39;outils qui apparaît</li><li>Le texte est marqué avec un style de suppression (barré rouge)</li></ol><p><strong>Ajouter une annotation Replace</strong> :</p><ol><li>Sélectionnez avec la souris le texte à remplacer dans le plan</li><li>Cliquez sur le bouton <strong>Replace</strong> dans la barre d&#39;outils qui apparaît</li><li>Saisissez le contenu de remplacement dans le champ de saisie qui apparaît</li><li>Appuyez sur Entrée ou cliquez sur confirmer</li><li>Le texte original est marqué avec un style de remplacement (fond jaune), et le contenu de remplacement s&#39;affiche en dessous</li></ol><p><strong>Ajouter une annotation Comment</strong> :</p><ol><li>Sélectionnez avec la souris le texte à commenter dans le plan</li><li>Cliquez sur le bouton <strong>Comment</strong> dans la barre d&#39;outils qui apparaît</li><li>Saisissez le contenu du commentaire dans le champ de saisie qui apparaît</li><li>Appuyez sur Entrée ou cliquez sur confirmer</li><li>Le texte est marqué avec un style de commentaire (surbrillance bleue), et le commentaire s&#39;affiche dans la barre latérale</li></ol><p><strong>Ajouter un Global Comment</strong> :</p><ol><li>Cliquez sur le bouton <strong>Add Global Comment</strong> en haut à droite de la page</li><li>Saisissez le contenu du commentaire global dans le champ de saisie qui apparaît</li><li>Appuyez sur Entrée ou cliquez sur confirmer</li><li>Le commentaire s&#39;affiche dans la section « Global Comments » de la barre latérale</li></ol><p><strong>Ce que vous devriez voir</strong> :</p><ul><li>Après avoir sélectionné du texte, la barre d&#39;outils apparaît immédiatement (Delete, Replace, Comment)</li><li>Après avoir ajouté une annotation, le texte affiche le style correspondant (barré, couleur de fond, surbrillance)</li><li>La barre latérale affiche la liste de toutes les annotations, vous pouvez cliquer pour naviguer vers la position correspondante</li><li>Vous pouvez cliquer sur le bouton <strong>Supprimer</strong> à côté d&#39;une annotation pour la retirer</li></ul><h3 id="etape-4-approuver-le-plan" tabindex="-1">Étape 4 : Approuver le plan <a class="header-anchor" href="#etape-4-approuver-le-plan" aria-label="Permalink to &quot;Étape 4 : Approuver le plan&quot;">​</a></h3><p><strong>Si le plan est correct</strong> :</p><p>Cliquez sur le bouton <strong>Approve</strong> en bas de page.</p><p><strong>Ce que vous devriez voir</strong> :</p><ul><li>Le navigateur se ferme automatiquement (délai de 1,5 seconde)</li><li>Le terminal Claude Code/OpenCode affiche que le plan est approuvé</li><li>L&#39;IA continue l&#39;implémentation du plan</li></ul><div class="info custom-block"><p class="custom-block-title">Comportement de Approve</p><ul><li><strong>Claude Code</strong> : Envoie uniquement <code>{&quot;behavior&quot;: &quot;allow&quot;}</code>, les annotations sont ignorées</li><li><strong>OpenCode</strong> : Envoie <code>{&quot;behavior&quot;: &quot;allow&quot;}</code>, les annotations peuvent être envoyées comme notes (optionnel)</li></ul></div><h3 id="etape-5-rejeter-le-plan-request-changes" tabindex="-1">Étape 5 : Rejeter le plan (Request Changes) <a class="header-anchor" href="#etape-5-rejeter-le-plan-request-changes" aria-label="Permalink to &quot;Étape 5 : Rejeter le plan (Request Changes)&quot;">​</a></h3><p><strong>Si le plan nécessite des modifications</strong> :</p><ol><li>Ajoutez les annotations nécessaires (Delete, Replace, Comment)</li><li>Cliquez sur le bouton <strong>Request Changes</strong> en bas de page</li><li>Le navigateur affiche une boîte de dialogue de confirmation</li></ol><p><strong>Ce que vous devriez voir</strong> :</p><ul><li>La boîte de dialogue de confirmation affiche « Send X annotations to AI? »</li><li>Après confirmation, le navigateur se ferme automatiquement</li><li>Le terminal Claude Code/OpenCode affiche le contenu du retour</li><li>L&#39;IA modifie le plan en fonction du retour</li></ul><div class="tip custom-block"><p class="custom-block-title">Comportement de Request Changes</p><ul><li><strong>Claude Code</strong> et <strong>OpenCode</strong> : Les deux envoient <code>{&quot;behavior&quot;: &quot;deny&quot;, &quot;message&quot;: &quot;...&quot;}</code></li><li>Les annotations sont converties en texte Markdown structuré</li><li>L&#39;IA modifie le plan et appelle à nouveau ExitPlanMode/submit_plan</li></ul></div><h3 id="etape-6-consulter-le-contenu-du-retour-optionnel" tabindex="-1">Étape 6 : Consulter le contenu du retour (optionnel) <a class="header-anchor" href="#etape-6-consulter-le-contenu-du-retour-optionnel" aria-label="Permalink to &quot;Étape 6 : Consulter le contenu du retour (optionnel)&quot;">​</a></h3><p>Si vous souhaitez voir le contenu du retour envoyé par Plannotator à l&#39;IA, consultez le terminal :</p><p><strong>Claude Code</strong> :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Plan rejected by user</span></span>
<span class="line"><span>Please modify the plan based on the following feedback:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[Contenu structuré des annotations]</span></span></code></pre></div><p><strong>OpenCode</strong> :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;feedback&gt;</span></span>
<span class="line"><span>[Contenu structuré des annotations]</span></span>
<span class="line"><span>&lt;/feedback&gt;</span></span></code></pre></div><h2 id="point-de-controle-✅" tabindex="-1">Point de contrôle ✅ <a class="header-anchor" href="#point-de-controle-✅" aria-label="Permalink to &quot;Point de contrôle ✅&quot;">​</a></h2><p>Après avoir terminé les étapes ci-dessus, vous devriez pouvoir :</p><ul><li>[ ] Après que l&#39;IA déclenche la révision de plan, le navigateur ouvre automatiquement l&#39;interface Plannotator</li><li>[ ] Sélectionner du texte de plan et ajouter des annotations Delete, Replace, Comment</li><li>[ ] Ajouter un Global Comment</li><li>[ ] Consulter toutes les annotations dans la barre latérale et naviguer vers la position correspondante</li><li>[ ] Cliquer sur Approve, le navigateur se ferme, l&#39;IA continue l&#39;implémentation</li><li>[ ] Cliquer sur Request Changes, le navigateur se ferme, l&#39;IA modifie le plan</li></ul><p><strong>Si une étape échoue</strong>, consultez :</p><ul><li><a href="./../../faq/common-problems/">Problèmes courants</a></li><li><a href="./../../start/installation-claude-code/">Guide d&#39;installation Claude Code</a></li><li><a href="./../../start/installation-opencode/">Guide d&#39;installation OpenCode</a></li></ul><h2 id="pieges-a-eviter" tabindex="-1">Pièges à éviter <a class="header-anchor" href="#pieges-a-eviter" aria-label="Permalink to &quot;Pièges à éviter&quot;">​</a></h2><p><strong>Erreur courante 1</strong> : Après avoir sélectionné du texte, la barre d&#39;outils n&#39;apparaît pas</p><p><strong>Cause</strong> : Vous avez peut-être sélectionné du texte dans un bloc de code, ou le texte sélectionné traverse plusieurs éléments.</p><p><strong>Solution</strong> :</p><ul><li>Essayez de sélectionner du texte dans un seul paragraphe ou élément de liste</li><li>Pour les blocs de code, utilisez une annotation Comment, ne sélectionnez pas sur plusieurs lignes</li></ul><p><strong>Erreur courante 2</strong> : Après avoir ajouté une annotation Replace, le contenu de remplacement ne s&#39;affiche pas</p><p><strong>Cause</strong> : Le champ de saisie du contenu de remplacement n&#39;a peut-être pas été correctement soumis.</p><p><strong>Solution</strong> :</p><ul><li>Après avoir saisi le contenu de remplacement, appuyez sur Entrée ou cliquez sur le bouton de confirmation</li><li>Vérifiez si le contenu de remplacement s&#39;affiche dans la barre latérale</li></ul><p><strong>Erreur courante 3</strong> : Après avoir cliqué sur Approve ou Request Changes, le navigateur ne se ferme pas</p><p><strong>Cause</strong> : Erreur serveur ou problème réseau possible.</p><p><strong>Solution</strong> :</p><ul><li>Vérifiez s&#39;il y a des messages d&#39;erreur dans le terminal</li><li>Fermez manuellement le navigateur</li><li>Si le problème persiste, consultez <a href="./../../faq/troubleshooting/">Dépannage</a></li></ul><p><strong>Erreur courante 4</strong> : L&#39;IA ne modifie pas selon les annotations après avoir reçu le retour</p><p><strong>Cause</strong> : L&#39;IA n&#39;a peut-être pas correctement compris l&#39;intention des annotations.</p><p><strong>Solution</strong> :</p><ul><li>Essayez d&#39;utiliser des annotations plus explicites (Replace est plus explicite que Comment)</li><li>Utilisez Comment pour ajouter des explications détaillées</li><li>Si le problème persiste, rejetez à nouveau le plan et ajustez le contenu des annotations</li></ul><p><strong>Erreur courante 5</strong> : Après avoir ajouté plusieurs annotations Delete, l&#39;IA n&#39;a supprimé qu&#39;une partie du contenu</p><p><strong>Cause</strong> : Il peut y avoir des chevauchements ou des conflits entre plusieurs annotations Delete.</p><p><strong>Solution</strong> :</p><ul><li>Assurez-vous que les plages de texte de chaque annotation Delete ne se chevauchent pas</li><li>Si vous devez supprimer un grand bloc de contenu, sélectionnez le paragraphe entier en une seule fois</li></ul><h2 id="resume-du-cours" tabindex="-1">Résumé du cours <a class="header-anchor" href="#resume-du-cours" aria-label="Permalink to &quot;Résumé du cours&quot;">​</a></h2><p>La révision de plan est la fonctionnalité principale de Plannotator, vous permettant de réviser visuellement les plans générés par l&#39;IA :</p><p><strong>Opérations principales</strong> :</p><ol><li><strong>Déclenchement</strong> : L&#39;IA appelle <code>ExitPlanMode</code> ou <code>submit_plan</code>, le navigateur ouvre automatiquement l&#39;interface</li><li><strong>Parcours</strong> : Consultez le contenu du plan dans l&#39;interface visuelle (format Markdown)</li><li><strong>Annotation</strong> : Sélectionnez du texte, ajoutez Delete, Replace, Comment ou Global Comment</li><li><strong>Décision</strong> : Cliquez sur Approve (approuver) ou Request Changes (rejeter)</li><li><strong>Retour</strong> : Les annotations sont converties en données structurées, l&#39;IA continue ou modifie le plan selon le retour</li></ol><p><strong>Types d&#39;annotations</strong> :</p><ul><li><strong>Delete</strong> : Supprimer le contenu non nécessaire</li><li><strong>Replace</strong> : Remplacer par un meilleur contenu</li><li><strong>Comment</strong> : Commenter un passage sans exiger de modification</li><li><strong>Global Comment</strong> : Commentaire global, non lié à un texte spécifique</li></ul><p><strong>Types de décision</strong> :</p><ul><li><strong>Approve</strong> : Le plan est correct, approbation directe (Claude Code ignore les annotations)</li><li><strong>Request Changes</strong> : Des modifications sont nécessaires, les annotations sont envoyées à l&#39;IA</li></ul><h2 id="apercu-du-prochain-cours" tabindex="-1">Aperçu du prochain cours <a class="header-anchor" href="#apercu-du-prochain-cours" aria-label="Permalink to &quot;Aperçu du prochain cours&quot;">​</a></h2><blockquote><p>Dans le prochain cours, nous apprendrons <strong><a href="./../plan-review-annotations/">Ajouter des annotations de plan</a></strong>.</p><p>Vous apprendrez :</p><ul><li>Comment utiliser précisément les annotations Delete, Replace, Comment</li><li>Comment ajouter des annotations d&#39;images</li><li>Comment modifier et supprimer des annotations</li><li>Les meilleures pratiques et cas d&#39;utilisation courants des annotations</li></ul></blockquote><hr><h2 id="annexe-reference-du-code-source" tabindex="-1">Annexe : Référence du code source <a class="header-anchor" href="#annexe-reference-du-code-source" aria-label="Permalink to &quot;Annexe : Référence du code source&quot;">​</a></h2><details><summary><strong>Cliquez pour afficher l&#39;emplacement du code source</strong></summary><blockquote><p>Date de mise à jour : 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Fonctionnalité</th><th>Chemin du fichier</th><th>Numéros de ligne</th></tr></thead><tbody><tr><td>Interface de révision de plan</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/editor/App.tsx#L1-L200" target="_blank" rel="noreferrer"><code>packages/editor/App.tsx</code></a></td><td>1-200</td></tr><tr><td>Définition des types d&#39;annotations</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/types.ts#L1-L70" target="_blank" rel="noreferrer"><code>packages/ui/types.ts</code></a></td><td>1-70</td></tr><tr><td>Serveur de révision de plan</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L91-L310" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>91-310</td></tr><tr><td>API : Obtenir le contenu du plan</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L132-L134" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>132-134</td></tr><tr><td>API : Approuver le plan</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L201-L277" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>201-277</td></tr><tr><td>API : Rejeter le plan</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L280-L309" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>280-309</td></tr><tr><td>Composant Viewer</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/Viewer.tsx#L1-L100" target="_blank" rel="noreferrer"><code>packages/ui/components/Viewer.tsx</code></a></td><td>1-100</td></tr><tr><td>Composant AnnotationPanel</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/AnnotationPanel.tsx#L1-L50" target="_blank" rel="noreferrer"><code>packages/ui/components/AnnotationPanel.tsx</code></a></td><td>1-50</td></tr></tbody></table><p><strong>Types clés</strong> :</p><ul><li><code>AnnotationType</code> : Énumération des types d&#39;annotations (DELETION, INSERTION, REPLACEMENT, COMMENT, GLOBAL_COMMENT) (<code>packages/ui/types.ts:1-7</code>)</li><li><code>Annotation</code> : Interface d&#39;annotation (<code>packages/ui/types.ts:11-33</code>)</li><li><code>Block</code> : Interface de bloc de plan (<code>packages/ui/types.ts:35-44</code>)</li></ul><p><strong>Fonctions clés</strong> :</p><ul><li><code>startPlannotatorServer()</code> : Démarre le serveur de révision de plan (<code>packages/server/index.ts:91</code>)</li><li><code>parseMarkdownToBlocks()</code> : Analyse le Markdown en Blocks (<code>packages/ui/utils/parser.ts</code>)</li></ul><p><strong>Routes API</strong> :</p><ul><li><code>GET /api/plan</code> : Obtenir le contenu du plan (<code>packages/server/index.ts:132</code>)</li><li><code>POST /api/approve</code> : Approuver le plan (<code>packages/server/index.ts:201</code>)</li><li><code>POST /api/deny</code> : Rejeter le plan (<code>packages/server/index.ts:280</code>)</li></ul><p><strong>Règles métier</strong> :</p><ul><li>Claude Code n&#39;envoie pas les annotations lors de l&#39;approbation (<code>apps/hook/server/index.ts:132</code>)</li><li>OpenCode peut envoyer les annotations comme notes lors de l&#39;approbation (<code>apps/opencode-plugin/index.ts:270</code>)</li><li>Les annotations sont toujours envoyées lors du rejet du plan (<code>apps/hook/server/index.ts:154</code>)</li></ul></details>`,112)])])}const g=n(o,[["render",l]]);export{m as __pageData,g as default};
